changeSet.sql:
ALTER TABLE discussion DROP CONSTRAINT IF EXISTS uknlcwyn2relkgw95s8okgpkqrt;
ALTER TABLE discussion_category DROP CONSTRAINT IF EXISTS uk6cjmvjyh5jc9bfnn8i9wggbo5;

DO $$
DECLARE
    r RECORD;
BEGIN
    FOR r IN
        SELECT con.conname, cls.relname
        FROM pg_constraint con
        JOIN pg_class cls ON con.conrelid = cls.oid
        JOIN pg_namespace nsp ON cls.relnamespace = nsp.oid
        WHERE nsp.nspname = current_schema()
          AND cls.relname IN ('discussion', 'discussion_category')
          AND con.contype = 'u'
          AND con.conname ~ '^uk[a-z0-9]{20,}$'
    LOOP
        EXECUTE format('ALTER TABLE %I DROP CONSTRAINT %I', r.relname, r.conname);
    END LOOP;
END
$$;
